#!/usr/bin/env node
/**
 * Merges scripts/enrich-results.json into src/data/hikes.ts (real dist/asc/route)
 * and src/data/hikeElevation.generated.ts (real elevation profiles, kept in a
 * separate generated file so hikes.ts stays human-sized/reviewable).
 */
import { readFileSync, writeFileSync } from "fs";
import { join, dirname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const resultsPath = join(__dirname, "enrich-results.json");
const hikesPath = join(__dirname, "../src/data/hikes.ts");
const elevationPath = join(__dirname, "../src/data/hikeElevation.generated.ts");

const results = JSON.parse(readFileSync(resultsPath, "utf-8"));
let hikesSrc = readFileSync(hikesPath, "utf-8");

const elevationEntries = [];
const notices = {
  tanzboedeli:
    "Letzter Aufstieg zum Aussichtskanzel ist im Kartenmaterial nicht als durchgehender Weg erfasst (steiler, teils weglos) — Strecke angenähert.",
  gemmi:
    "Strecke ins Lämmerenboden ist im Kartenmaterial nicht durchgehend erfasst — Strecke angenähert.",
};

for (const r of results) {
  const idPattern = new RegExp(`(id: "${r.id}"[\\s\\S]*?)(\\n {2}\\},)`);
  const match = hikesSrc.match(idPattern);
  if (!match) {
    console.warn(`Could not locate block for ${r.id}, skipping.`);
    continue;
  }
  let block = match[1];

  if (r.ok) {
    const newDist = (r.distanceM / 1000).toFixed(1);
    const newAsc = Math.round(r.ascentM);
    block = block.replace(/dist: [\d.]+, asc: [\d.]+,/, `dist: ${newDist}, asc: ${newAsc},`);

    const routeLiteral = r.route.map(([lat, lng]) => `[${lat.toFixed(5)}, ${lng.toFixed(5)}]`).join(", ");
    block = block.replace(/route: \[\[.*?\]\],/s, `route: [${routeLiteral}],`);

    elevationEntries.push(
      `  ${r.id}: [\n${r.elevation
        .map(
          (p) =>
            `    { distanceM: ${p.distanceM.toFixed(1)}, elevationM: ${p.elevationM.toFixed(1)}, lat: ${p.lat.toFixed(5)}, lng: ${p.lng.toFixed(5)} },`,
        )
        .join("\n")}\n  ],`,
    );
  } else if (notices[r.id]) {
    block = block.replace(/(route: \[\[.*?\]\],)/s, `$1\n    routeNotice: "${notices[r.id]}",`);
  }

  hikesSrc = hikesSrc.slice(0, match.index) + block + match[2] + hikesSrc.slice(match.index + match[0].length);
}

writeFileSync(hikesPath, hikesSrc);

const elevationSrc = `import type { ElevationPoint } from "../types";

/** Generated by scripts/enrich-hikes.mjs + scripts/merge-enrichment.mjs — real elevation profiles from OpenRouteService. Do not hand-edit. */
export const HIKE_ELEVATION: Record<string, ElevationPoint[]> = {
${elevationEntries.join("\n")}
};
`;
writeFileSync(elevationPath, elevationSrc);

console.log(`Updated ${hikesPath}`);
console.log(`Wrote ${elevationPath} (${elevationEntries.length} hikes)`);
